"PST" as $tz
| ($tz 
    | if . == "UTC" then 0
      elif . == "EST" then (-5 * 3600)
      elif . == "EDT" then (-4 * 3600)
      elif . == "CST" then (-6 * 3600)
      elif . == "CDT" then (-5 * 3600)
      elif . == "MST" then (-7 * 3600)
      elif . == "MDT" then (-6 * 3600)
      elif . == "PST" then (-8 * 3600)
      elif . == "PDT" then (-7 * 3600)
      elif . == "AKST" then (-9 * 3600)
      elif . == "AKDT" then (-8 * 3600)
      elif . == "HST" then (-10 * 3600)
      elif . == "GMT" then 0
      elif . == "BST" then (1 * 3600)
      elif . == "CET" then (1 * 3600)
      elif . == "CEST" then (2 * 3600)
      elif . == "EET" then (2 * 3600)
      elif . == "EEST" then (3 * 3600)
      elif . == "JST" then (9 * 3600)
      else 0 end
  ) as $offset
| . as $input
| ($offset + now) as $adjustedTime
| ($adjustedTime | strftime("%Y-%m-%dT%H:%M:%S")) as $ts
| $input.body.user.name as $user
| {
    "value": $input.body.actions[0].value,
    "api": (
      if $input.body.actions[0].value == "benign" then 
        "/web/api/v2.1/threats/incident"
      else 
        "/web/api/v2.1/threats/mitigate/" +
          (if $input.body.actions[0].value == "rollback" then "rollback-remediation" else $input.body.actions[0].value end)
      end
    ),
    "user": $user,
    "payload": {
      "data": (
        if $input.body.actions[0].value == "benign" then 
          { "incidentStatus": "resolved", "analystVerdict": "false_positive" }
        else 
          {}
        end
      ),
      "filter": {
        "ids": ["{{edr-or-identity-alert.data.externalId}}"]
      }
    },
    "timestamp": $ts,
    "timezone": $tz,
    "log_message": ("[" + $ts + " " + $tz + "]: Mitigation action [" + $input.body.actions[0].value + "] sent successfully by " + $user + ". \n")
}

def make_button($key; $obj):
  { "type": "button",
    "text": { "type": "plain_text",
              "text": (
                if $key == "quarantine" then
                  if $obj.title == "Unquarantine" then
                    ":large_green_circle: " + ($obj.title // "")
                  elif (($obj.disabledReason // "") | contains("This action is not available for threats with pending"))
                    then ":large_yellow_circle: " + ($obj.title // "")
                  else
                    ":black_circle: " + ($obj.title // "")
                  end
                else
                  if ($obj.isDisabled | not) then
                    ":black_circle: " + ($obj.title // "")
                  elif ($obj.disabledReason == "This action is not available for remediated threats" or 
                         $obj.disabledReason == "This action is not available for killed threats" or
                         $obj.disabledReason == "This action is not available for rolled-back threats")
                    then ":large_green_circle: " + ($obj.title // "")
                  elif (($obj.disabledReason // "") | contains("This action is not available for threats with pending"))
                    then ":large_yellow_circle: " + ($obj.title // "")
                  else
                    ":black_circle: " + ($obj.title // "")
                  end
                end
              )
            },
    "value": $key
  }
;

def is_button_creatable($obj):
  $obj.isAvailable and (
    ($obj.isDisabled | not)
    or ($obj.disabledReason == "This action is not available for remediated threats" 
        or $obj.disabledReason == "This action is not available for killed threats"
        or $obj.disabledReason == "This action is not available for rolled-back threats"
        or (($obj.disabledReason // "") | contains("This action is not available for threats with pending"))
    )
  )
;

.body.data.alertAvailableActions.data
| {
    kill: (
      first(.[] | select(.title == "Kill")
        | { description, disabledReason, isDisabled, title }
      )
      | { description: .description,
          disabledReason: .disabledReason,
          isDisabled: .isDisabled,
          title: .title,
          isAvailable: (.title != null)
        }
    ),
    quarantine: (
      first(.[] | select(.title == "Quarantine" or .title == "Unquarantine")
        | { description, disabledReason, isDisabled, title }
      )
      | { description: .description,
          disabledReason: .disabledReason,
          isDisabled: .isDisabled,
          title: .title,
          isAvailable: (.title != null)
        }
    ),
    remediate: (
      first(.[] | select(.title == "Remediate")
        | { description, disabledReason, isDisabled, title }
      )
      | { description: .description,
          disabledReason: .disabledReason,
          isDisabled: .isDisabled,
          title: .title,
          isAvailable: (.title != null)
        }
    ),
    rollback: (
      first(.[] | select(.title == "Rollback")
        | { description, disabledReason, isDisabled, title }
      )
      | { description: .description,
          disabledReason: .disabledReason,
          isDisabled: .isDisabled,
          title: .title,
          isAvailable: (.title != null)
        }
    ),
    benign: { description: null, disabledReason: null, isDisabled: false, title: "Benign", isAvailable: true }
}
| . as $actions
| $actions + {
    blocks: [
      {
        "type": "actions",
        "elements": (
          (if is_button_creatable($actions.kill) then [make_button("kill"; $actions.kill)] else [] end)
          + (if is_button_creatable($actions.quarantine) then [make_button("quarantine"; $actions.quarantine)] else [] end)
          + (if is_button_creatable($actions.remediate) then [make_button("remediate"; $actions.remediate)] else [] end)
          + (if is_button_creatable($actions.rollback) then [make_button("rollback"; $actions.rollback)] else [] end)
          + (if is_button_creatable($actions.benign) then [make_button("benign"; $actions.benign)] else [] end)
          + [
              {
                "type": "button",
                "text": { "type": "plain_text", "text": "Cancel" },
                "action_id": "cancel",
                "value": "cancel",
                "style": "danger"
              }
            ]
        )
      }
    ]
}

.body.data[0].networkStatus as $status
| (if $status == "connected" then "disconnect" else "reconnect" end) as $action
| $action | split("") as $chars
| ($chars[0] | ascii_upcase) as $first
| ($chars[1:] | join("")) as $rest
| ($first + $rest) as $action_label
| (
    if $status == "connected" then "🟢 | CONNECTED"
