  alert(id: $id) {
    id
    name @skip(if: $skipName)
    result @skip(if: $skipResult)
    status @skip(if: $skipStatus)
    rawData @skip(if: $skipRawData)
    severity @skip(if: $skipSeverity)
    createdAt @skip(if: $skipCreatedAt)
    updatedAt @skip(if: $skipUpdatedAt)
    externalId @skip(if: $skipExternalId)
    detectedAt @skip(if: $skipDetectedAt)
    lastSeenAt @skip(if: $skipLastSeenAt)
    description @skip(if: $skipDescription)
    firstSeenAt @skip(if: $skipFirstSeenAt)
    storylineId @skip(if: $skipStorylineId)
    analystVerdict @skip(if: $skipAnalystVerdict)
    classification @skip(if: $skipClassification)
    confidenceLevel @skip(if: $skipConfidenceLevel)
    assignee @skip(if: $skipAssignee) {
      email
