      ...ProcessDetail
      __typename
    }
    realTime @skip(if: $skipRealTime) {
      ...RealTime
      __typename
    }
    counters @skip(if: $skipCounters) {
      ...Counter
      __typename
    }
    analytics @skip(if: $skipAnalytics) {
      ...Analytics
      __typename
    }
    indicators @skip(if: $skipIndicators) {
      ...Indicator
      __typename
    }
    observables @skip(if: $skipObservables) {
      ...Observable
      __typename
    }
